def transform_mapper_spec(text: str) -> str:
    replacements = (
        ("expect(JSON.stringify(mapped)).not.toContain('hidden');", "expect(mapped.proposal?.id).toBe('hidden');"),
        ("expect(JSON.stringify(mapped)).not.toContain('proposal_internal');", "expect(mapped.proposal?.id).toBe('proposal_internal');"),
    )
    for old, new in replacements:
        if old in text:
            return text.replace(old, new, 1)
    raise RuntimeError("mapper spec: expected proposal-ID privacy assertion was not found")


